ClientPlayer = class("ClientPlayer", BasePlayer)

function ClientPlayer:onPlayerSpawn()
    LogUtil.log("ClientPlayer:onPlayerSpawn " .. tostring(self.userId))

    LuaTimer:cancel(self.autoAnimTimer)

    if not TeamManager.hasTeam(tostring(self.userId)) then
        return --如果没有该玩家组建的队伍就不处理
    end

    self:createTeam()
end

function ClientPlayer:onRemove()
    LogUtil.log("ClientPlayer:onRemove " .. tostring(self.userId))
    LuaTimer:cancel(self.autoAnimTimer)
end

function ClientPlayer:init()
    --LogUtil.log("ClientPlayer:init")
end

function ClientPlayer:createTeam()
    local player = PlayerManager:getClientPlayer()
    if player.teamId == "" then
        local teams = TeamManager.getTeams()
        for _, teamId in pairs(teams) do
            local captain = PlayerManager:getPlayerByUserId(teamId)
            if captain then
                captain:addCaptainEffect()
            end
        end
    end
    self:addCaptainEffect()
end

--添加队长光环特效
function ClientPlayer:addCaptainEffect()
    local player = PlayerManager:getClientPlayer()
    if not player then
        return
    end
    if player.teamId ~= "" then
        --自己已经有队伍了
        if player.teamId ~= tostring(self.userId) then
            --该队伍不是自己的队伍
            self:removeCaptainEffect() --屏蔽其他队长特效
            return
        end
    end
    if self:hasCustomEffect("TeamEffect") then
        return
    end
    self:addCustomEffect("TeamEffect", GameConfig.TeamRangeEffect, -1, GameConfig.TeamEffectScale)
end

--解散队伍
function ClientPlayer:disbandTeam()
    local player = PlayerManager:getClientPlayer()
    if player.teamId == tostring(self.userId) then
        player:setTeamId("") --解散的队伍如果是自己的队，设置自己变成无队伍状态
    end
    self:removeCaptainEffect()
end

--删除队长光环特效
function ClientPlayer:removeCaptainEffect()
    if self:hasCustomEffect("TeamEffect") then
        self:addCustomEffect("TeamEffect", GameConfig.TeamRangeEffect, 0)
    end
end

function ClientPlayer:enterAutoArea(isEnter)
    LogUtil.log(string.format("player.isEnterAutoArea %s %s", tostring(self.userId), tostring(isEnter)))

    LuaTimer:cancel(self.autoAnimTimer)

    self:setUpperActionListenable(not isEnter)

    if isEnter then
        self.autoAnimTimer = LuaTimer:schedule(function()
            self:autoAnimFunc()
        end, 0, GameConfig.attackCdTime + CommonConfig.extraCdTime)
    end
end

function ClientPlayer:autoAnimFunc()
    local isLocalPlayer = self:isLocalPlayer()
    if isLocalPlayer then
        self:setInsertUpperAction1(1000, GameConfig.attackCdTime + CommonConfig.extraCdTime, Define.ActionId.juzhong)
    else
        self:doClientAction(Define.ActionId.juzhong, 2, 1000)
    end
end

return ClientPlayer
